() => {
  // Find the accepted answer element
  const acceptedNote = document.querySelector('.js-accepted-answer-indicator, .accepted-answer, [data-isaccepted="true"]');
  let acceptedAnswer = null;

  // Try finding by the accepted checkmark
  const answers = document.querySelectorAll('.answer');
  for (const ans of answers) {
    if (ans.querySelector('.js-accepted-answer-indicator') || ans.classList.contains('accepted-answer') || ans.getAttribute('data-isaccepted') === 'true') {
      acceptedAnswer = ans;
      break;
    }
  }

  if (!acceptedAnswer) {
    // Try finding by vote score - the first answer with vote score showing
    const voteScores = document.querySelectorAll('.js-vote-count');
    return 'Could not find accepted answer. Vote scores: ' + Array.from(voteScores).slice(0, 3).map(e => e.textContent.trim()).join(', ');
  }

  const codeBlocks = acceptedAnswer.querySelectorAll('pre code, pre');
  const voteCount = acceptedAnswer.querySelector('.js-vote-count');
  const author = acceptedAnswer.querySelector('.user-details a');

  return {
    voteCount: voteCount ? voteCount.textContent.trim() : 'not found',
    author: author ? author.textContent.trim() : 'not found',
    codeBlockCount: codeBlocks.length,
    codeBlockHTML: Array.from(codeBlocks).map((b, i) => `Block ${i+1}: ${b.tagName} - ${b.textContent.substring(0, 50)}`)
  };
}

