input.function:
() => {
  // Find accepted answer
  const answers = document.querySelectorAll('.answer');
  let acceptedAnswer = null;
  for (const ans of answers) {
    if (ans.querySelector('.js-accepted-answer-indicator') || ans.classList.contains('accepted-answer') || ans.getAttribute('data-isaccepted') === 'true') {
      acceptedAnswer = ans;
      break;
    }
  }

  // Get original author (the "answered by" section, not the "edited by")
  const userInfo = acceptedAnswer.querySelectorAll('.post-signature');
  let originalAuthor = 'not found';
  // The last user-details is typically the original poster
  const allUserDetails = acceptedAnswer.querySelectorAll('.user-details a');
  // Usually format is: [edited by user], [answered by user]
  // The "answered" one is typically in the last .post-signature that has "answered"
  const postSigs = acceptedAnswer.querySelectorAll('.post-signature');
  for (const sig of postSigs) {
    if (sig.textContent.includes('answered')) {
      const link = sig.querySelector('.user-details a');
      if (link) originalAuthor = link.textContent.trim();
    }
  }

  // Get total answers count
  const answersHeader = document.querySelector('#answers-header h2, .answers-subheader h2, [data-answercount]');
  const answersCount = document.querySelector('#answers-header')?.textContent?.trim() || 
                       document.querySelector('.answers-subheader')?.textContent?.trim() ||
                       'not found';

  // Count distinct code blocks - pre elements (each pre wraps one code block)
  const preBlocks = acceptedAnswer.querySelectorAll('pre');
  const codeBlocks = acceptedAnswer.querySelectorAll('pre code');

  return {
    originalAuthor,
    allUserLinks: Array.from(allUserDetails).map(a => a.textContent.trim()),
    answersCountText: answersCount,
    preCount: preBlocks.length,
    preCodeCount: codeBlocks.length,
  };
}

